mapper.select:
SELECT a.category_id AS id, a.category_id AS categoryId, b.category_name AS categoryName, b.category_en_name AS categoryEnName, b.category_name_path AS categoryNamePath, JSON_ARRAYAGG( JSON_OBJECT( 'typeId', c.sub_attribute_type_id, 'list', ( SELECT JSON_ARRAYAGG( JSON_OBJECT( 'level', sub_a.level, 'attributeId', sub_a.attribute_category_id, 'attributeName', sub_c.attribute_name, 'attributeEnName', sub_c.attribute_en_name ) ) FROM kol_category_attribute_relation sub_a INNER JOIN kol_attribute sub_c ON sub_a.attribute_category_id = sub_c.id WHERE sub_a.category_id = a.category_id AND sub_c.attribute_type_id = c.sub_attribute_type_id AND sub_a.is_delete = 0 AND sub_c.is_delete = 0 ) ) ) AS dataListStr FROM ( SELECT DISTINCT category_id FROM kol_category_attribute_relation WHERE is_delete = 0 ) a INNER JOIN kol_category b ON a.category_id = b.id INNER JOIN ( SELECT DISTINCT attribute_type_id AS sub_attribute_type_id FROM kol_attribute WHERE id IN ( SELECT attribute_category_id FROM kol_category_attribute_relation WHERE is_delete = 0 ) AND is_delete = 0 ) c ON EXISTS ( SELECT 1 FROM kol_category_attribute_relation sub_a INNER JOIN kol_attribute sub_c ON sub_a.attribute_category_id = sub_c.id WHERE sub_a.category_id = a.category_id AND sub_c.attribute_type_id = c.sub_attribute_type_id AND sub_a.is_delete = 0 AND sub_c.is_delete = 0
AND EXISTS ( SELECT 1 FROM kol_attribute c2 WHERE c2.id = a.attribute_category_id AND c2.attribute_name LIKE CONCAT('%', #{model.subAttributeName}, '%') )
)
AND b.category_code = #{model.rootPathCode}
AND a.category_id = #{model.categoryId}
GROUP BY a.category_id, b.category_name, b.category_name_path ORDER BY b.category_name_path

SELECT attribute_category_id
FROM kol_category_attribute_relation
WHERE category_id = #{categoryId}

SELECT b.*, a.`level`, a.category_id, c.category_name FROM kol_category_attribute_relation a LEFT JOIN kol_attribute b on a.attribute_category_id = b.id LEFT JOIN kol_category c ON a.category_id = c.id
WHERE a.category_id IN (
#{item}
)

SELECT a.category_id AS id, a.category_id AS categoryId, b.category_name AS categoryName, b.category_en_name AS categoryEnName, b.category_name_path AS categoryNamePath, JSON_ARRAYAGG( JSON_OBJECT( 'typeId', c.sub_attribute_type_id, 'list', ( SELECT JSON_ARRAYAGG( JSON_OBJECT( 'level', sub_a.level, 'attributeId', sub_a.attribute_category_id, 'attributeName', sub_c.attribute_name, 'attributeEnName', sub_c.attribute_en_name ) ) FROM kol_category_attribute_relation sub_a INNER JOIN kol_attribute sub_c ON sub_a.attribute_category_id = sub_c.id WHERE sub_a.category_id = a.category_id AND sub_c.attribute_type_id = c.sub_attribute_type_id AND sub_a.is_delete = 0 AND sub_c.is_delete = 0 ) ) ) AS dataListStr FROM ( SELECT DISTINCT category_id FROM kol_category_attribute_relation WHERE is_delete = 0 ) a INNER JOIN kol_category b ON a.category_id = b.id INNER JOIN ( SELECT DISTINCT attribute_type_id AS sub_attribute_type_id FROM kol_attribute WHERE id IN ( SELECT attribute_category_id FROM kol_category_attribute_relation WHERE is_delete = 0 ) AND is_delete = 0 ) c ON EXISTS ( SELECT 1 FROM kol_category_attribute_relation sub_a INNER JOIN kol_attribute sub_c ON sub_a.attribute_category_id = sub_c.id WHERE sub_a.category_id = b.id AND sub_c.attribute_type_id = c.sub_attribute_type_id AND sub_a.is_delete = 0 AND sub_c.is_delete = 0
AND EXISTS ( SELECT 1 FROM kol_attribute c2 WHERE c2.id = sub_a.attribute_category_id AND c2.attribute_name LIKE CONCAT('%', #{model.subAttributeName}, '%') )
)
AND b.parent_id = '0'
AND b.category_code = #{model.rootPathCode}
GROUP BY a.category_id, b.category_name, b.category_name_path ORDER BY b.category_name_path
